import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.HttpRequest
import akka.http.scaladsl.unmarshalling.Unmarshal

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem()

  val routes = Http().route {
    case req @ POST -> "/webhook" =>
      Unmarshal(req.entity).to[String] flatMap { userUrl =>
        val request = HttpRequest(uri = userUrl)
        Http().singleRequest(request).map { response =>
          response.discardEntityBytes()
          resp(200, "OK")
        } recover { case t: Throwable => resp(500, s"Internal Server Error: ${t.getMessage}") }
